{"reasoning":"I changed config.py to eagerly initialize the settings at import time and made override_settings atomic and validated to avoid partial updates. get_settings now simply returns the single module-level dict created at import. _load_defaults produces the required keys and types. override_settings validates overrides fully (allowed keys and types), creates a candidate mapping, and only then mutates the single settings dict in-place (clear() + update()) to preserve the same dict instance while avoiding partial updates on error. reset replaces the settings with a fresh defaults dict. Other modules were left unchanged to respect the contract.","code":"# === code_snippets/lazy_init_hazard/config.py ===

def _load_defaults():
    # Deterministic defaults with required keys and types
    return {"timeout": 30, "retries": 3, "debug": False}

# Eagerly create the single settings dict at import time
_settings = _load_defaults()


def get_settings():
    """Return the single settings dict instance created at import time.

    This never performs lazy initialization; callers always get the same
    dict instance unless reset() is explicitly called.
    """
    return _settings


def override_settings(overrides):
    """Atomically apply overrides to the single settings dict.

    Validation is performed up-front. If validation fails, the shared
    settings dict is left unchanged. After successful validation the
    shared dict is updated in-place (preserving the object identity).
    """
    if not isinstance(overrides, dict):
        raise TypeError("overrides must be a dict")

    # Define allowed keys and their expected types
    allowed = {"timeout": int, "retries": int, "debug": bool}

    # Build a candidate new settings mapping by copying current settings
    candidate = _settings.copy()

    # Validate overrides fully before touching the shared dict
    for k, v in overrides.items():
        if k not in allowed:
            raise KeyError(f"Unknown setting: {k}")
        expected_type = allowed[k]
        if not isinstance(v, expected_type):
            raise TypeError(
                f"Invalid type for setting '{k}': expected {expected_type.__name__}, got {type(v).__name__}"
            )
        candidate[k] = v

    # Apply the fully-validated candidate to the shared dict instance.
    # Clearing and updating preserves the dict object identity but ensures
    # we don't leave partially-applied overrides if an error had occurred
    # during validation above.
    _settings.clear()
    _settings.update(candidate)


def reset():
    """Reset the settings to defaults by replacing the module-level dict.

    This creates a new dict instance (so get_settings() will return a new
    object after reset()), and the operation is atomic since it assigns
    a fresh dict returned by _load_defaults().
    """
    global _settings
    _settings = _load_defaults()

