from metrics import get_snapshots, get_count


def build_report():
    snaps = get_snapshots()
    return {
        "total_processed": get_count("processed"),
        "total_high": get_count("high_priority"),
        "per_record_snapshots": snaps,
        "n_snapshots": len(snaps),
    }


def verify_consistency():
    snaps = get_snapshots()
    prev = 0
    for s in snaps:
        proc = s.get("processed", 0)
        # snapshots must be non-decreasing
        if proc < prev:
            return False
        prev = proc
    total = get_count("processed")
    # If there are snapshots, the last snapshot must equal the total processed.
    if snaps:
        if snaps[-1].get("processed", 0) != total:
            return False
    else:
        # No snapshots should correspond to zero total processed
        if total != 0:
            return False
    return True
